const Q_AGRICULTURE_2024_MODEL_I=[{"id": "objective>Agriculture>2024 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factor that determines the rate of agriculture development in a country is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">readiness of farmers to adopt viable agricultural research results</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity of herbicides used in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of machinery available in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of raw materials for industries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factor that determines the rate of agricultural development in a country is the readiness of farmers to adopt viable agricultural research results. This is because the adoption of new and improved farming techniques and practices can significantly increase agricultural productivity and efficiency, leading to increased agricultural development. The other options do not directly determine the rate of agricultural development.</div>", "topic": "HISTORY OF AGRICULTURAL DEVELOPMENT IN WEST AFRICA"}, {"id": "objective>Agriculture>2024 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic feature of subsistence agriculture is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply of labour by farm families</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholesale of farm harvest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchasing of seeds for planting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diseases control</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic feature of subsistence agriculture is the supply of labour by farm families. Subsistence agriculture is a type of farming where the farmers focus on growing enough food to feed themselves and their families. The output is mostly for local requirements with little or no surplus trade. The labour in subsistence farming is often provided by the family members.</div>", "topic": "MEANING AND SCOPE OF AGRICULTURE"}, {"id": "objective>Agriculture>2024 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will retain the greatest amount of water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay soil has the smallest particle size among the options and therefore has the highest water holding capacity. The small particles in clay soil are packed closely together, which limits the amount of air that can get in. This means that water is held in the soil for longer, making it more available for plants to use.</div>", "topic": "ROCKS AND SOIL FORMATION : PHYSICAL PROPERTIES OF SOIL"}, {"id": "objective>Agriculture>2024 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of a disc plough to which discs are connected is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scraper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">furrow wheel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The standard is the part of the plough that holds the disc and allows it to rotate. It is the main support structure for the disc.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factors affecting formation of soil include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">topography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catena</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factors affecting the formation of soil include organisms, time, and topography. Catena is not a factor in soil formation. Instead, it is a term used in soil science to describe a sequence of soils of different types, occurring on a slope, each one resulting from a different balance between soil-forming processes.</div>", "topic": "ROCKS AND SOIL FORMATION : PHYSICAL PROPERTIES OF SOIL"}, {"id": "objective>Agriculture>2024 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following defines agriculture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the raising of farm animals by rural communities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a way of life by which farmers produced food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the raising of crops to satisfy human needs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the science and art of farming to satisfy human needs</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture is defined as the science and art of farming to satisfy human needs. It involves the cultivation of plants and the rearing of animals for food, fiber, medicinal plants, and other products used to sustain and enhance human life. Therefore, the option 'the science and art of farming to satisfy human needs' is the most comprehensive and accurate definition of agriculture.</div>", "topic": "MEANING AND SCOPE OF AGRICULTURE"}, {"id": "objective>Agriculture>2024 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a piece of land is leased to a farmer, the land is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">given to him as subsidy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase on loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocated on a rental basis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">given as a gift</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a piece of land is leased to a farmer, it means the farmer is given the right to use the land for a specified period in exchange for payment. This is known as renting or allocation on a rental basis. It is not a subsidy, loan, or gift.</div>", "topic": "LAND"}, {"id": "objective>Agriculture>2024 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of crops will thrive in areas with high rainfall?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cotton, cowpea and groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">millet, maize and cotton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guinea corn, cowpea and maize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa, oil palm and rubber</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cocoa, oil palm, and rubber are all crops that thrive in areas with high rainfall. These crops require a lot of water to grow, which is why they do well in areas with high rainfall. Cotton, cowpea, and groundnut, on the other hand, are crops that can tolerate drier conditions. Similarly, millet, maize, and cotton are crops that can grow in areas with moderate rainfall. Guinea corn, cowpea, and maize also require moderate rainfall to grow.</div>", "topic": "FACTORS OF AGRICULTURAL PRODUCTION"}, {"id": "objective>Agriculture>2024 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil-borne diseases could be controlled in the nursery by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mulching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manuring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat treatment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of shade</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil solarization is the possible way to control or prevent these soil pathogens through raising of soil temperature. Clean thin and transparent polythene sheet can be spread over the nursery soil. Solar energy will be trapped in this method and heats the soil This removes all the soil pathogens</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below illustrates a reproductive process in a farm animal. Study it and answer the question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lactation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gestation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gestation refers to the period of pregnancy or the time it takes for female animals, particularly livestock, to carry and develop their offspring before giving birth.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2024 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capping is a cultural practice carried out in the cultivation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carrot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cassava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potato</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yam</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capping The practice of using dry grasses or pieces of wood to cover the spot where yam sett or seed yam is planted either on ridge or mound is called capping.</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2024 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not correct about the importance of agriculture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply of food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of the raw materials for agro-based industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serving as main source of foreign exchange</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture is not the main source of foreign exchange for many countries, especially those with a diversified economy. While it can contribute to foreign exchange through the export of agricultural products, it is not the main source. The main sources of foreign exchange are usually industries like oil and gas, manufacturing, and services.</div>", "topic": "IMPORTANCE OF AGRICULTURE"}, {"id": "objective>Agriculture>2024 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The roles of government in the development of agriculture include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">recommending loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of subsidies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of farm settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">training of farmers children</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government plays a significant role in the development of agriculture through various means such as recommending loans, providing subsidies, and establishing farm settlements. However, training of farmers' children is not a direct role of the government in agricultural development. This is more related to the education sector, although agricultural education can be promoted by the government.</div>", "topic": "HISTORY OF AGRICULTURAL DEVELOPMENT IN WEST AFRICA"}, {"id": "objective>Agriculture>2024 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are characteristics of quartz except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">being granular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">having shiny surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">being glass-like</div>", "<div style=\"font-family:Cambria;font-size:17px;\">having cleavage</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quartz is a mineral that is known for its hardness and glass-like appearance. It does not have cleavage, which is the ability of a mineral to break along flat surfaces. This characteristic is not present in quartz, hence the correct answer is 'having cleavage'.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factors which affect the number and the activities of soil micro-organisms include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">topography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil moisture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil aeration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of soil acidity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number and activities of soil micro-organisms are influenced by factors such as soil moisture, soil aeration, and degree of soil acidity. However, topography, which refers to the physical features of land, does not directly affect the number and activities of soil micro-organisms. Therefore, the correct answer is 'topography'.</div>", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS"}, {"id": "objective>Agriculture>2024 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wastage of agricultural products during harvesting period is due mainly to inadequate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transport facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">storage and processing facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agricultural education and extension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">implementation of government policies on agriculture</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wastage of agricultural products during the harvesting period is mainly due to inadequate storage and processing facilities. Without proper storage and processing facilities, harvested crops can easily spoil or get damaged, leading to wastage. While transport facilities, agricultural education and extension, and implementation of government policies on agriculture can also contribute to wastage, they are not the main cause.</div>", "topic": "CROP PESTS : METHODS OF PREVENTION AND CONTROL"}, {"id": "objective>Agriculture>2024 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The provision of farm inputs to farmers by government can best be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsidy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The provision of farm inputs to farmers by the government can best be described as a subsidy. A subsidy is a form of financial aid or support extended to an economic sector (or institution, business, or individual) generally with the aim of promoting economic and social policy. In this case, the government is providing financial aid to farmers in the form of farm inputs to promote agricultural activities.</div>", "topic": "FARM MANAGEMENT"}, {"id": "objective>Agriculture>2024 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following uses of land should be given more attention in Nigeria for self sufficiency in food production?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">construction of roads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">building of research centres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of wildlife</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of agriculture and forestry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The establishment of agriculture and forestry directly contributes to food production. Agriculture involves the cultivation of plants and rearing of animals for food, fiber, medicinal plants, and other products used to sustain and enhance human life. Forestry, on the other hand, involves the management of forests for the production of timber and non-timber forest products. Both of these uses of land contribute significantly to food production.</div>", "topic": "ANIMAL NUTRITION"}, {"id": "objective>Agriculture>2024 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does not fit into the agricultural use of land?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forest establishment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">animal production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mining is not typically considered an agricultural use of land. While it does involve the use of land, it does not involve the cultivation of plants or the rearing of animals, which are the primary activities associated with agriculture.</div>", "topic": "LAND"}, {"id": "objective>Agriculture>2024 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagrams below illustrate different sources of farm power. Study them and answer the question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the illustrated sources of farm power is the cheapest</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I is the sources of farm power that is cheapest because it uses crude tool</div>", "topic": "MECHANIZATION AND SOURCES OF FARM POWER : SOURCES OF FARM POWER"}, {"id": "objective>Agriculture>2024 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss is a metamorphic rock formed from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandstone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss is a metamorphic rock that is formed from granite. Metamorphic rocks are formed from the transformation of existing rock types in a process called metamorphism, which means 'change in form'. The original rock (protolith) is subjected to heat and pressure causing profound physical and/or chemical change. In this case, the protolith is granite.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A difference between physical and chemical weathering is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is a change in the mineral composition of rock in physical weathering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mineral composition of rock is changed in chemical weathering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonation is necessary in physical weathering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind is necessary in chemical weathering</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chemical weathering involves the interaction of rock with mineral solutions (chemicals) to change the composition of rocks. In this process, water interacts with minerals to create various chemical reactions and transform the rocks.</div>", "topic": "ECOLOGY"}, {"id": "objective>Agriculture>2024 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main factors responsible for rock weathering in the desert are high temperature and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">animal activity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root growth</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Physical forces in the desert that break down rocks include the daily heating and cooling of rocks on the surface, expansion of plant root in cracks, the freezing and melting of ice in cracks, and exposure to wind and precipitation (particularly during storms).</div>", "topic": "ROLES OF GOVERNMENT AND NGOS IN AGRICULTURAL DEVELOPMENT"}, {"id": "objective>Agriculture>2024 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Decomposition of soil organic matter is mainly caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bacterial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nematodes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decomposers are microorganisms that decompose/convert the dead remains of plants and animals into humus. <br/> ∙ Bacteria are a common example of decomposers. <br/> They are crucial in cleaning the waste of dead plants and animals and converting them into humus, which increases the soil's nutrients.</div>", "topic": "ROCKS AND SOIL FORMATION : PHYSICAL PROPERTIES OF SOIL"}, {"id": "objective>Agriculture>2024 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ranging poles used in farm surveying have characteristic</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">green and white bands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue and white bands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red and white bands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black and red bands</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ranging poles are used to mark areas and to set out straight lines on the field. They are also used to mark points which must be seen from a distance, in which case a flag may be attached to improve the visibility. <br/> Ranging poles are straight round stalks, 3 to 4 cm thick and about 2 m long. They are made of wood or metal. Ranging poles can also be home made from strong straight bamboo or tree branches. <br/> REMEMBER: Ranging poles may never be curved. <br/> Ranging poles are usually painted with alternate red-white or black-white bands. If possible, wooden ranging poles are reinforced at the bottom end by metal points.</div>", "topic": "ROCKS AND SOIL FORMATION : PHYSICAL PROPERTIES OF SOIL"}, {"id": "objective>Agriculture>2024 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Igneous rock formed within the crust are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">guartzite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcanic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plutonic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stratified</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plutonic rocks form from magma that cools and solidifies within the crust of the Earth, as opposed to volcanic rocks, which form from lava that cools on the Earth's surface.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following soil water is tightly held to the surface of the soil particles?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravitational water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capillary water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superfluous water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hygroscopic water is the type of soil water that is tightly held to the surface of the soil particles. It is held by adsorption and is not available to plants because it is held too tightly for the roots to absorb. It is also not affected by gravity.</div>", "topic": "SOIL WATER AND SOIL CONSERVATION : SOIL WATER"}, {"id": "objective>Agriculture>2024 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following process will not lead to the loss of nutrient from the soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mulching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harvesting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leaching</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mulching does not lead to the loss of nutrients from the soil. Instead, it helps to conserve soil moisture, reduce erosion, and can contribute to the health of the soil by decomposing into organic matter. The other options, erosion, harvesting, and leaching, all lead to nutrient loss from the soil.</div>", "topic": "CROP NUTRITION"}, {"id": "objective>Agriculture>2024 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the nitrogen cycle , nitrite is oxidized to nitrate by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrobacter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrosomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">azotobacter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhizobium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the nitrogen cycle, nitrite is oxidized to nitrate by the bacteria Nitrobacter. This process is known as nitrification. Nitrosomonas is involved in the first step of nitrification, which is the oxidation of ammonia  to nitrite. Azotobacter and Rhizobium are nitrogen-fixing bacteria, they convert atmospheric nitrogen  into a form that plants can use.</div>", "topic": "CROP NUTRITION"}, {"id": "objective>Agriculture>2024 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below illustrates a method of compost making. Study it and answer the question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The method of compost milking illustrated in the diagram is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The method of compost milking heap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sheet</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The method of compost milking illustrated in the diagram is pit</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2024 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will not lead to loss of nitrogen compound from the soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crop removal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lodging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leaching</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lodging refers to the falling over of crops, usually due to wind or heavy rain. This does not lead to a loss of nitrogen compounds from the soil. Nitrogen loss from the soil can occur through crop removal, burning, and leaching. Leaching is the process where nutrients are washed out from the soil by rain or irrigation. Burning can lead to the loss of nitrogen as it can volatilize and escape into the atmosphere. Crop removal can also lead to nitrogen loss as the nutrient is taken up by the plants and removed when the crop is harvested.</div>", "topic": "CROP NUTRITION"}, {"id": "objective>Agriculture>2024 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following group of basic amenities should be provided in rural areas for improved agricultural productivity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water, electricity and health care centres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electricity, guest houses and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">health care centres, water and airport</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Roads, airport and recreation centers.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The provision of basic amenities such as water, electricity, and health care centres in rural areas can significantly improve agricultural productivity. Access to clean water is essential for both crop irrigation and livestock rearing. Electricity can power machinery and equipment that can increase the efficiency of farming practices. Health care centres can provide medical services to rural populations, ensuring that they are healthy and able to work on their farms. The other options, such as guest houses, airports, and recreation centers, while beneficial in some ways, are not as directly linked to agricultural productivity.</div>", "topic": "ANIMAL PRODUCTION~~FACTORS OF AGRICULTURAL PRODUCTION"}, {"id": "objective>Agriculture>2024 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government laws and reforms are aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing agriculture production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling farm profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discouraging investment in agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging importation of agriculture produce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government laws and reforms in the agricultural sector are primarily aimed at increasing agricultural production. This can be achieved through a variety of means, such as providing subsidies to farmers, implementing policies that encourage sustainable farming practices, and investing in agricultural research and development. While controlling farm profits, discouraging investment in agriculture, and encouraging the importation of agricultural produce may be the effects of certain policies, they are not the primary aim of government laws and reforms.</div>", "topic": "ROLES OF GOVERNMENT AND NGOS IN AGRICULTURAL DEVELOPMENT : GOVERNMENT PROGRAMMES"}, {"id": "objective>Agriculture>2024 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to ensure that crop and animals disease are not transferred across international boundaries, government must</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have programmes on agricultural education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endeavours to produce only disease resistance species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have and enforce quarantine service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase survelliance of its border by security agents</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To prevent the transfer of crop and animal diseases across international boundaries, governments must have and enforce quarantine services. Quarantine is a restriction on the movement of people and goods which is intended to prevent the spread of disease or pests. It is often used in connection to disease and illness, preventing the movement of those who may have been exposed to a communicable disease, but do not have a confirmed medical diagnosis.</div>", "topic": "CROP DISEASES : CONTROL METHODS"}, {"id": "objective>Agriculture>2024 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium deficiency in cereal crops is indicated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">browning of leaves from the tips and margins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellowing of younger leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purpling of leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white and irregular spots on leaves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium deficiency symptoms on cereal grains appear as a burning or scorching of the older, lower leaves. The burning begins at the leaf tip and continues down the leaf margin.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The replacement of traditional farming methods with modern methods is a step in agricultural</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expansion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversification</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The replacement of traditional farming methods with modern methods is a step in agricultural development. This is because the introduction of modern methods such as mechanization, use of improved seeds, fertilizers, and pesticides, among others, improves productivity and efficiency in agriculture, hence leading to its development.</div>", "topic": "FARM MACHINERY AND IMPLEMENTS"}, {"id": "objective>Agriculture>2024 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is not correct about land use act?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land cannot be used for any purpose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government has control over unused land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it does not lead to land fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it aims at re-allocation of land for farming purposes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'land cannot be used for any purpose' is not correct about the Land Use Act. The Land Use Act is a policy that gives the government control over land in the country with the aim of ensuring equitable use and management. It does not prohibit the use of land; rather, it regulates how land is used to ensure it is used for the benefit of all citizens and to prevent land fragmentation.</div>", "topic": "LAND TENURE SYSTEM"}, {"id": "objective>Agriculture>2024 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main aim of wildlife management is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent extinction of species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide lots of cheap protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generate foreign exchange through exportation of meat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the population of trypanosome parasites.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wildlife management is the process of keeping wild species and the ecosystems they inhabit healthy and vibrant. The main aim of wildlife management is to ensure the survival of all species and to maintain the balance of ecosystems. This includes preventing the extinction of species.</div>", "topic": "FISHERIES AND WILDLIFE"}, {"id": "objective>Agriculture>2024 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes does not lead to the physical disintegration of rock? the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heating and cooling of rock surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expansion and contraction of rock minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of cracks and cervices in the rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid cooling and solidification of rocks</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The physical disintegration of rock, also known as physical or mechanical weathering, involves the breakdown of rocks and soils through direct contact with atmospheric conditions, such as heat, water, ice and pressure. The rapid cooling and solidification of rocks is not a process that leads to the physical disintegration of rock. Instead, it is a process that leads to the formation of igneous rocks. When magma or lava cools and solidifies rapidly, it forms a type of igneous rock known as extrusive igneous rock.</div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2024 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Although clay soil are rich in nutrient, they are not good for most agricultural crop production because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">do not release their nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are too compact and poorly aerated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lose their nutrient too readily after rain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains too much iron, aluminium and boron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay soils are not good for most agricultural crop production because they are too compact and poorly aerated. Clay particles are very small and tightly packed together, which limits the amount of air and water that can penetrate the soil. This can lead to poor root growth and reduced nutrient uptake by plants.</div>", "topic": "ROCKS AND SOIL FORMATION"}];
